### 模板：写一次代码，适用所有类型

在机器人编程中，很多算法对不同数据类型是通用的。比如 PID 控制器可以用于 float 也可以用于 double；滤波器可以处理标量也可以处理向量。**模板**让你只写一份代码就能处理所有类型。

### 函数模板

```cpp
#include <cmath>
#include <vector>
#include <algorithm>

// 函数模板: 适用于任何数值类型
template<typename T>
T clamp(T value, T min_val, T max_val) {
    return std::max(min_val, std::min(value, max_val));
}

// 使用:
// double torque = clamp(raw_torque, -10.0, 10.0);  // double 版
// float angle = clamp(raw_angle, -3.14f, 3.14f);   // float 版
// int pwm = clamp(raw_pwm, 0, 255);                 // int 版

// 向量 clamp
template<typename VectorType>
VectorType clamp_vector(const VectorType& v, 
                         typename VectorType::Scalar min_val,
                         typename VectorType::Scalar max_val) {
    return v.cwiseMax(min_val).cwiseMin(max_val);
}
```

### 类模板

```cpp
// PID 控制器模板: 可用于标量和向量
template<typename T>
class PIDController {
public:
    PIDController(T kp, T ki, T kd, T dt)
        : kp_(kp), ki_(ki), kd_(kd), dt_(dt),
          integral_{}, prev_error_{} {}

    T compute(const T& setpoint, const T& measured) {
        T error = setpoint - measured;
        integral_ += error * dt_;
        T derivative = (error - prev_error_) / dt_;
        prev_error_ = error;
        return kp_ * error + ki_ * integral_ + kd_ * derivative;
    }

    void reset() { integral_ = T{}; prev_error_ = T{}; }

private:
    T kp_, ki_, kd_, dt_;
    T integral_, prev_error_;
};

// 标量 PID
// PIDController<double> joint_pid(10.0, 0.1, 1.0, 0.001);
// double torque = joint_pid.compute(target_angle, current_angle);

// 向量 PID (控制多个关节)
// PIDController<Eigen::VectorXd> multi_pid(kp_vec, ki_vec, kd_vec, dt);
// Eigen::VectorXd torques = multi_pid.compute(target_joints, current_joints);
```

### 模板特化

```cpp
// 通用版本
template<typename T>
std::string type_name() { return "unknown"; }

// 特化版本
template<>
std::string type_name<double>() { return "float64"; }

template<>
std::string type_name<float>() { return "float32"; }

template<>
std::string type_name<int>() { return "int32"; }
```

### 可变参数模板 (Variadic Templates)

```cpp
#include <iostream>

// 日志函数: 接受任意数量和类型的参数
template<typename... Args>
void robot_log(const char* level, const char* fmt, Args&&... args) {
    printf("[%s] ", level);
    printf(fmt, std::forward<Args>(args)...);
    printf("\n");
}

// 使用:
// robot_log("INFO", "Joint %d: angle=%.3f, torque=%.3f", 0, 1.57, 0.5);
// robot_log("WARN", "Collision detected at link %s", "forearm");
```

### CRTP：编译时多态

```cpp
// Curiously Recurring Template Pattern
// 在机器人中用于: 控制器基类、传感器接口等
// 优势: 零开销多态 (没有虚函数表的开销)

template<typename Derived>
class SensorBase {
public:
    void update() {
        static_cast<Derived*>(this)->update_impl();
    }

    auto read() {
        return static_cast<Derived*>(this)->read_impl();
    }
};

class IMU : public SensorBase<IMU> {
    friend class SensorBase<IMU>;
    void update_impl() { /* 读取 IMU 硬件 */ }
    double read_impl() { return 9.81; }
};

class Encoder : public SensorBase<Encoder> {
    friend class SensorBase<Encoder>;
    void update_impl() { /* 读取编码器 */ }
    double read_impl() { return 1.57; }
};

// 编译时就确定了调用哪个实现, 没有虚函数开销
// 对 1kHz 控制循环很重要 (每微秒都很宝贵)
```

### 模板在机器人中的典型应用

```
Eigen 库 (全部基于模板):
  Matrix<double, 3, 3>  → Matrix3d
  Matrix<float, Dynamic, 1> → VectorXf
  Matrix<int, 4, 4> → Matrix4i

ROS2 消息 (模板化的发布/订阅):
  Publisher<JointState>::SharedPtr pub;
  Subscription<Image>::SharedPtr sub;

智能指针 (标准库模板):
  unique_ptr<Robot> robot;
  shared_ptr<Camera> cam;

容器 (标准库模板):
  vector<double> trajectory;
  map<string, double> joint_map;
  array<double, 7> joint_angles;  // 固定大小, 栈上分配
```

### 练习
1. 实现一个模板化的低通滤波器类
2. 用 CRTP 实现零开销的控制器接口
3. 实现一个可变参数的传感器融合函数

### 参考答案

**1. 模板化低通滤波器**

```cpp
// low_pass_filter.h
template<typename T>
class LowPassFilter {
public:
    explicit LowPassFilter(double cutoff_freq, double dt)
        : alpha_(dt / (1.0 / (2.0 * M_PI * cutoff_freq) + dt)),
          initialized_(false) {}

    T filter(const T& input) {
        if (!initialized_) {
            filtered_ = input;
            initialized_ = true;
        } else {
            // y[n] = alpha * x[n] + (1-alpha) * y[n-1]
            filtered_ = alpha_ * input + (1.0 - alpha_) * filtered_;
        }
        return filtered_;
    }

    void reset() { initialized_ = false; }

private:
    double alpha_;
    bool initialized_;
    T filtered_;
};

// 使用:
// LowPassFilter<double> torque_filter(10.0, 0.001);  // 10Hz截止, 1kHz采样
// double smooth_torque = torque_filter.filter(raw_torque);
//
// LowPassFilter<Eigen::Vector3d> imu_filter(5.0, 0.005);  // 向量版
// auto smooth_accel = imu_filter.filter(raw_accel);
```

**2. CRTP 零开销控制器**

```cpp
template<typename Derived, typename StateType, typename ActionType>
class ControllerBase {
public:
    ActionType compute(const StateType& state, const StateType& target) {
        return static_cast<Derived*>(this)->compute_impl(state, target);
    }
};

class PDController : public ControllerBase<PDController, double, double> {
    friend class ControllerBase<PDController, double, double>;
public:
    PDController(double kp, double kd) : kp_(kp), kd_(kd), prev_error_(0) {}
private:
    double compute_impl(const double& state, const double& target) {
        double error = target - state;
        double d_error = error - prev_error_;
        prev_error_ = error;
        return kp_ * error + kd_ * d_error;
    }
    double kp_, kd_, prev_error_;
};

// PDController pd(10.0, 1.0);
// double torque = pd.compute(current_angle, target_angle);
// 编译后和直接调用 compute_impl 完全等价, 零开销
```

**3. 可变参数传感器融合**

```cpp
#include <tuple>
#include <cmath>

// 加权平均融合任意数量的传感器读数
template<typename T>
T weighted_average(T value, double weight) {
    return value * weight;
}

template<typename T, typename... Rest>
T weighted_average(T first_val, double first_weight, 
                    Rest... rest) {
    return first_val * first_weight + weighted_average(rest...);
}

// 使用:
// double fused_angle = weighted_average(
//     encoder_angle, 0.7,    // 编码器权重 70%
//     imu_angle, 0.2,        // IMU 权重 20%
//     vision_angle, 0.1      // 视觉权重 10%
// );
```
